// Package imports:
import 'package:in_app_purchase/in_app_purchase.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/subscription_controller.dart';
import 'package:baseball_detector_flutter/data/models/in_app_purchase/current_entitlement.dart';

class FakeSubscriptionController extends SubscriptionController {
  FakeSubscriptionController({this.appAccountToken, this.webOrderLineItemId});

  final String? appAccountToken;
  final String? webOrderLineItemId;

  @override
  Future<CurrentEntitlement?> build() async {
    if (appAccountToken == null && webOrderLineItemId == null) {
      return null;
    }
    return CurrentEntitlement(
      appAccountToken: appAccountToken,
      webOrderLineItemID: webOrderLineItemId,
    );
  }

  @override
  Future<void> updateCurrentEntitlement() async {}

  @override
  Future<bool> purchaseSubscription(ProductDetails productDetails) async =>
      true;
}

