import 'package:baseball_detector_flutter/data/models/team_plan.dart';
import 'package:baseball_detector_flutter/data/result.dart';

class FakeTeamListController extends TeamListController {
  FakeTeamListController({this.result});

  final Result<Failure, List<Team>>? result;

  @override
  AsyncValue<Result<Failure, List<Team>>> build() => AsyncValue.data(
        result ??
            Right(
              [
                Team(
                  id: 'teamId',
                  name: 'Demo Team',
                  teamType: TeamType.single,
                  teamPlan: TeamPlan(
                      id: 'plan',
                      isActive: true,
                      endDate: DateTime.utc(2030, 2, 1),
                      currentUsage: 0,
                      extraBalls: 0,
                      plan: Plan(
                        isPaid: true,
                        isActive: true,
                        maxBalls: 250,
                      )),
                )
              ],
            ),
      );

  @override
  Future<void> refreshKeepingPrevious() async {}
}

