// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/plan_controller.dart';
import 'package:baseball_detector_flutter/data/models/app_store_plan.dart';
import 'package:baseball_detector_flutter/data/models/team_plan.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/views/hooks/use_widget_ref.dart';

String usePlanNameFromPlanType(PlanType? planType) {
  final context = useContext();

  if (planType == null) return '';

  return switch (planType) {
    PlanType.light => context.l10n.subscription_page__plan_light,
    PlanType.standard => context.l10n.subscription_page__plan_standard,
    PlanType.premium => context.l10n.subscription_page__plan_premium,
    PlanType.forMultipleTeam => '',
  };
}

String usePlanNameFromTeamPlan(TeamPlan? teamPlan) {
  final context = useContext();
  final plan = teamPlan?.plan;

  if (plan == null) {
    return context.l10n.settings_page__no_plan_name;
  }

  return switch (plan.planType) {
    PlanType.light => context.l10n.subscription_page__plan_light,
    PlanType.standard => context.l10n.subscription_page__plan_standard,
    PlanType.premium => context.l10n.subscription_page__plan_premium,
    PlanType.forMultipleTeam =>
      plan.name ?? context.l10n.settings_page__no_plan_name,
  };
}

String? usePlanNameFromPlanId(String? id) {
  if (id == null) return null;

  final context = useContext();
  final ref = useWidgetRef();

  // Plan ID から Plan を取得（Riverpod が自動的にキャッシュ）
  final planAsync = ref.watch(planByIdProvider(id));

  return planAsync.when(
    data: (plan) {
      if (plan == null) return null;

      return switch (plan.planType) {
        PlanType.light => context.l10n.subscription_page__plan_light,
        PlanType.standard => context.l10n.subscription_page__plan_standard,
        PlanType.premium => context.l10n.subscription_page__plan_premium,
        PlanType.forMultipleTeam => null,
      };
    },
    loading: () => null,
    error: (_, __) => null,
  );
}

